var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"그 나이에 벌써 낙엽을 다섯 번 베는 경지라니. 정말 장하구나, 사나에.","JPN":"その歳でもう落ちゆく葉を五回斬るなんて。立派だね、早苗。","ENG":"Already able to slice falling leaves five times at that age... Impressive, Sanae.","TWN":"小小年紀竟然已經可以砍五次落葉，很厲害喔，早苗。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"너라면 분명 하야미 가문이 찾는 검술의 경지에 닿을 수 있을 거야.","JPN":"あなたならきっと、速水家の求める剣術の高みに辿り着けるわ。","ENG":"I am confident that you will reach the pinnacle of the swordsmanship for which the Hayami family has yearned.","TWN":"你一定能達到速水家族追求的劍法境界。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"가문 어르신들도 그러셨어요.","JPN":"家門のみんなもそうおっしゃっていました。","ENG":"The elders have also said that to me.","TWN":"家族的長輩們也曾說過，"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"어머니께서 나나하라류의 경지를 깨닫지 못하니 제가 해야 한다고 합니다.","JPN":"母上が七原流の高みに辿り着けないから私がやらなければならないと。","ENG":"Mother was not able to reach it, so that it is my duty to do so.","TWN":"因為母親沒能領悟七原流的境界，所以必須由我來領悟。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"어머니만큼 강한 분도 없는데…… 그런 말은 이상합니다.","JPN":"母上ほど強い方もいないのに……おかしなことをいうものです。","ENG":"There is no one as strong as you... So those words sound strange to me.","TWN":"可是明明就沒人像母親一樣強……那句話好奇怪。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"……사나에. 엄마가 나나하라류 검술의 다른 이름이 뭐라고 했는지 기억하니?","JPN":"……早苗。七原流剣術の別名を教えたけれど、なんだったか覚えてる？","ENG":"...Sanae. Do you remember what the other name for Nanahara Style is?","TWN":"……早苗，你還記得媽媽說過，七原流劍法的另一個名稱是什麼嗎？"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"보이지 않는 것을 베는 검…… 입니다.","JPN":"見えないものを斬る剣……です。","ENG":"The blade that slashes the unseen...","TWN":"叫斬殺看不見之存在的劍……"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"그래, 나나하라류의 본질은 영혼을 베는 명부신의 검술이며, 눈에 보이지 않는 것을 베는 힘이야.","JPN":"そう、七原流の本質は魂を斬る冥府の神の剣術であり、目に見えないものを斬る力なの。","ENG":"Yes. The essence of the Nanahara Style is the Nether God's swordsmanship that slashes the soul. It slices what cannot be seen.","TWN":"沒錯，七原流的本質是斬殺靈魂的冥府神劍法，是斬殺肉眼看不見之存在的力量。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"하지만 엄마는 어둠 속에만 서면 너무 많은 후회와 잡념들에 사로잡혀버려.","JPN":"でも母は闇の中に立つと後悔と雑念ばかりに囚われてしまう。","ENG":"But whenever I stand in the dark, regrets and stray thoughts consume me.","TWN":"但是媽媽只要站在黑暗中，就會被太多的悔恨和雜念給干擾。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"그래서 눈앞이 캄캄해지면 쉽게 균형을 잃어버리고 말거든.","JPN":"それで、闇で目が見えなくなるとすぐバランスを崩すの。","ENG":"So, in the dark, I lose my balance easily.","TWN":"因此一旦眼前變黑，就很容易失去平衡。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"이 가면이 어둠을 밝혀 주긴 하지만, 도구에 의존하면 아무것도 깨달을 수 없으니까.","JPN":"この仮面が闇を照らしてはくれるけど、道具に頼ってはなにも悟ることはできないから。","ENG":"This mask fends away darkness, but one cannot reach the end while relying on such tools.","TWN":"這個面具雖然可以照亮黑暗，但太依賴工具的話反而就什麼都無法領悟到。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"하지만…… 강하고 굳센 내 딸이라면 할 수 있을 거야.","JPN":"でもね……心身ともに強い私の娘ならできるはずよ。","ENG":"But I believe... that you, strong and determined, will be able to.","TWN":"不過……我堅強的女兒一定能做到的。"},"stage":{"bg":"REEDS_FIELD_02","bgm":"CUTSCENE_LONELY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"KANADE_JAPAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"사나에, 너라면……","JPN":"早苗、あなたなら……","ENG":"Sanae, you...","TWN":"早苗，你的話……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KANADE_JAPAN_NULL_NULL","text":{"KOREA":"……어둠 앞에서도 평정을 잃지 않고, 사람들을 지킬 수 있을 거야.","JPN":"……闇の前でも平常心を失わずに、人々を守れる。","ENG":"...will be able to protect others in the face of darkness without disrupting your peace.","TWN":"……一定能在黑暗面前也不失去平靜，一定能保護別人。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ZENZIROU_NANA_NULL_NULL","text":{"KOREA":"커헉!","JPN":"がはっ！","ENG":"Kuh!","TWN":"咳咳！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENZIROU_NANA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"마사키!","JPN":"雅紀！","ENG":"Masaki!","TWN":"雅紀！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"한심하긴.","JPN":"情けないわね。","ENG":"Pathetic.","TWN":"真可笑。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"그런 장난감으로 친구를 지킬 수 있을 줄 알았어?","JPN":"そんなおもちゃで友達を守れるとでも思ったの？","ENG":"You think you'll be able to protect your friend with that?","TWN":"你以為用那種玩具能保護朋友嗎？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"처음엔 예견에도 없던 녀석들이 어디서 튀어나왔나 싶었는데 말이야.","JPN":"最初は予言になかった奴らがどこから来たのかと思ったけど。","ENG":"I was amused seeing someone who wasn't in my vision at first, but...","TWN":"我原本還在想，不存在於預言中的傢伙是從哪裡冒出來的？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"너희처럼 결과를 바꾸기엔 너무 작고 하찮은 변화라면 눈치를 못 챌 만도 하지.","JPN":"お前たちみたいに結果を覆すにはあまりにも小さく、どうってこともない変化なら、気づくわけないわよね。","ENG":"Now I realize you were so insignificant to the outcome that I didn't even notice you.","TWN":"不過像你們這種渺小到不足以改變結果的微小變化，我沒注意到你們也是很正常的。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"하아아앗!","JPN":"はあああっ！","ENG":"Haaaaa!!!!","TWN":"啊啊啊啊！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINATO_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L38_1","type":"dialog","speaker":"MINATO_NANA_NULL_NULL","text":{"KOREA":"쿨럭……","JPN":"ガハッ……","ENG":"*Cough*","TWN":"咳咳……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"후훗, 너무 떨지 마. 죽지 않을 만큼만 베었으니까.","JPN":"ふふっ、そう怖がらないで。死にはしないわ。","ENG":"Hah hah. What are you trembling about? I only wounded you just enough so that you'll live.","TWN":"呵呵，別緊張，我沒有砍到會死的程度。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"자 그럼, 아줌마도 마무리를……","JPN":"さて、おばさんにもとどめを……","ENG":"All right then, it's time to end her–","TWN":"那就也給那個大嬸來個痛……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"읏- 깜짝이야.","JPN":"ッ、びっくりした。","ENG":"Geez! You startled me.","TWN":"唔- 嚇我一跳。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"검……?","JPN":"刀……？","ENG":"A blade...?","TWN":"劍……？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"너…… 검을 쓸 줄 알았어?","JPN":"お前……刀を使えたの？","ENG":"You... knew how to wield a blade?","TWN":"你……會用劍？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"왜 그러지?","JPN":"どうした？","ENG":"What is it?","TWN":"怎麼？"},"stage":{"bg":"NANAHARA2_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"결말을 바꾸기엔 너무 작고 사소한 변화라서, 눈치채지 못했나?","JPN":"結末を覆すにはあまりにも小さく、どうってこともない変化で、気づけなかったか？","ENG":"Was this too insignificant for you to notice as well?","TWN":"因為是渺小到不足以改變結果的微小變化，所以沒注意到？"},"stage":{"bg":"NANAHARA2_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA2_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"어쩌다 한 번 먹힌 걸로 기어오르긴.","JPN":"まぐれで一太刀浴びせた程度で調子に乗って。","ENG":"Don't get so cocky. That was just a lucky blow.","TWN":"不過就打中一次而已，有什麼好囂張的。"},"stage":{"bg":"NANAHARA2_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"역겹게!","JPN":"うっとうしいわ！","ENG":"Disgusting!","TWN":"真令人噁心！"},"stage":{"bg":"NANAHARA2_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"쳐냈다고?","JPN":"受け流した？","ENG":"You blocked it?","TWN":"出招？"},"stage":{"bg":"NANAHARA2_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"절기…… 화권도월……","JPN":"絶技……花拳刀月……","ENG":"Exquisite... Flower Strike...","TWN":"絶技……花拳刀月……"},"stage":{"bg":"NANAHARA2_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"흥, 그깟 뻔한 칼질 따위 안 통해.","JPN":"ふん、そんな見え見えの剣技なんて通じないね。","ENG":"Hmph! Your blade is too easy to read.","TWN":"哼，那麼明顯的招數，對我沒用的。"},"stage":{"bg":"NANAHARA2_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"큭? 주먹이라고……?!","JPN":"くっ！？　拳……！？","ENG":"Kgh! A punch...?!","TWN":"唔？拳頭……？！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"커윽?!","JPN":"がはっ！？","ENG":"Kugh...?!","TWN":"咳咳？！"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_WATER_03"},{"id":"L24_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그런 상처를 입고도…… 막은 건가?","JPN":"それだけ傷を負っても……防ぐというのか？","ENG":"You still blocked it...? With those wounds?","TWN":"你傷成那樣……還擋得下？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"후후……","JPN":"ふふ……","ENG":"Hah hah.","TWN":"呵呵……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"아줌마가 처음이야.","JPN":"おばさんが初めてよ。","ENG":"You're the first, you know.","TWN":"大嬸是第一個。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"아버지께서 내게 방아쇠를 당기신 걸 마지막으로, 다른 인간의 의지로 힘을 발휘해본 적이 없었거든.","JPN":"お父様が私に引き金を引いた時が最後だった。それからは誰かの意志で力を発揮させられたことがなかったからね。","ENG":"After when father pulled the trigger on me, I've never used my full power on another human before.","TWN":"從父親對我扣下扳機後到現在，我從未因為他人的行為而發揮自己的力量過。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"목숨줄이 경각에 다다르면 그 능력도 날카로워지는 것이군.","JPN":"命の危険が迫るほどその能力も向上するということか。","ENG":"It gets sharper the more you inch towards death, I see.","TWN":"當生命受到威脅時，人的能力也會變強。"},"stage":{"bg":"NANAHARA2_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"그래, 원래는 적당히 상처만 입힐 생각이었는데……","JPN":"そう、適当に傷だけつけるつもりだったけど……","ENG":"Okay, I was planning on only giving you non-lethal cuts, but...","TWN":"很好，我原本只是想稍微給你點教訓就好……"},"stage":{"bg":"NANAHARA2_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"이젠 내 신경이 반사적으로 널 죽여버릴지도 몰라.","JPN":"これからは私の神経が反射的にお前を殺すかもしれない。","ENG":"Now, I might kill you out of reflex.","TWN":"但現在我很可能會因為神經反射而殺死你。"},"stage":{"bg":"NANAHARA2_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"바람의 목소리를 흉내 낼 뿐이면서, 그 힘의 방식은 무녀와 기분 나쁠 정도로 닮았구나.","JPN":"風の声を真似ているだけだというのに、その力は巫女に気持ち悪いほど似ているな。","ENG":"You can only mimic the power of the voice of wind. Yet, the way you use your powers is eerily similar to a priestess.","TWN":"真是令人生氣，明明只是在模仿風聲，那股力量的模式卻和巫女那麼像。"},"stage":{"bg":"NANAHARA2_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"흉내? 후훗, 고리타분하긴.","JPN":"真似ですって？　ふふっ、古臭いわね。","ENG":"Mimic? Hah hah. So old-fashioned, aren't you?","TWN":"模仿？呵呵，真是井底之蛙。"},"stage":{"bg":"NANAHARA2_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"신의 인자는 무궁한 가능성의 원천이야.","JPN":"神の因子は無限の可能性の源なの。","ENG":"The god factor is the source of infinite possibilities.","TWN":"神的因子是無限可能的來源。"},"stage":{"bg":"NANAHARA2_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"그런데 그 후손이라는 너희는 이런 좋은 힘을 발전시키려는 시도도 않았잖아?","JPN":"なのにその子孫であるお前たちはこんないい力を発展させてみようともしなかったわ。","ENG":"You claim to be descendants of god. But you haven't even attempted to harness this incredible power.","TWN":"但身為後裔的你們，卻從未嘗試過要發展這麼棒的力量不是嗎？"},"stage":{"bg":"NANAHARA2_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"불을 다룰 줄도 모르는 원숭이들처럼, 겁에 질린 채 오랫동안 정체되어 있었을 뿐이지.","JPN":"火の扱い方を知らないサルみたいに、怯えてずっとそのままにしてきたのよ。","ENG":"You're all like monkeys who don't even know how to use fire. Doing nothing because you're all too afraid.","TWN":"就像不會用火的猴子一樣，因為害怕而停滯不前。"},"stage":{"bg":"NANAHARA2_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"섭리에 따라, 신의 힘을 악용한 대가를 치르게 될 것이다.","JPN":"摂理に従い、神の力を悪用した代償を払うことになるだろう。","ENG":"As nature runs its course, you will be punished for abusing the powers of god.","TWN":"根據法則，你將為濫用神力付出代價。"},"stage":{"bg":"NANAHARA2_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"아하하하하!!","JPN":"アハハハハ！！","ENG":"Ah hah hah hah hah!","TWN":"哈哈哈哈哈！！"},"stage":{"bg":"NANAHARA2_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"업보를 운운하는 건 패배자들의 전형적인 말로지.","JPN":"業がどうこうっていうのは負け組の決まり文句よね。","ENG":"Just what a loser would say!","TWN":"失敗者才會說什麼報應不報應的。"},"stage":{"bg":"NANAHARA2_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"안 그래?","JPN":"違う？","ENG":"Don't you agree?","TWN":"不是嗎？"},"stage":{"bg":"NANAHARA2_02","bgm":"THEMA_CA_CHIFUYU_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};